import{_ as l}from"./nyalra_kb-7135827b.js";import{_ as r}from"./nyalra_no_mono-8344e451.js";import{_ as c,W as s,X as _,Y as i,Z as e,$ as t,a1 as a,a2 as m,a0 as d,C as o}from"./framework-91490e6a.js";const f={},u=e("figure",null,[e("img",{src:l,alt:"",tabindex:"0",loading:"lazy"}),e("figcaption")],-1),h={href:"https://tree-novel.com/works/episode/8162ac6a8266582975cbb07875de0cfd.html",target:"_blank",rel:"noopener noreferrer"},k=e("p",null,"这是在互联网中栖息的不可思议生物·Nyalra于深夜写下的有关互联网、独居生活以及除此之外的事物的图文随笔。",-1),g=d('<hr><p>我觉得，在创作中「努力」和「品味」之间的区别是残酷的。</p><p>当我住在合租房的时候，有一位渴望成为小说家的人（曾经获得奖项并在商业杂志上发表短篇小说），他有段时间感到沮丧。作为一种自我激励，他喃喃自语：「我（在小说上）真的很努力了啊……」 ，而另一位合租的人却悄悄地说：「小说不是光努力就行的，对吧。」。</p><p>他并不是在讽刺或恶语，因为他是一个非常坦诚的人，所以他只是坦率地表达了对对方话语的意见。他说的一点也没有错。但是，当这样的事实突然摆在你面前时，你可能会感到震惊。我当时也觉得「哦……」很吃惊。</p><p>是的，创作并不是「努力了就能收获赞扬」的东西。说到底，能够在商业领域发表作品的作家，哪个不是很努力，或者曾经很努力啊。借『第一神拳』的台词来说：「努力的人并不一定都会成功，但成功的人都是努力过的。」 努力在这里是前提条件，因此「我努力过了」不能成为读者或用户的评价标准。</p><p>有时候，没有刻意用心的作品反而反响更好；反之，过于固执和拘泥可能导致最终作品变得混乱难懂。在一定程度上，能够客观评价作品的能力和努力是分别被需要的，那种能抓到文章巧妙之点的能力可能被称为「品味」。</p><p>因此，如果你肯定自己「我努力过了」，实际上相当于承认「我努力过了，但我没有品味」。那么，「小说不是光努力就行的，对吧。」这句话反而是在解场。虽然不确定说这句话的人是否有意识到这一点。</p><p>“品味”是一个非常复杂的概念。有些人天生拥有敏锐的感觉，而有些人即使非常努力也可能变得无趣。在小说领域，很难区分，但在漫画领域，相比于简单易懂地象征着努力程度的画技，更重要的是构图和对白等品味，及风格和魄力的魅力。然而，品味是一个模糊的概念，谁也不能将其量化，甚至不知道如何磨练或拓展它。这是非常残酷的事实。</p><p>甚至可以说，画技或写作技巧可以通过「努力」来获得的，但与时间和金钱无关的「品味」可能只是与生俱来的。这是否已经进入了天赋的领域？</p><p>然而，人类具有学习的能力。这是一种模式学习。通过了解许多作品，体验许多事情，通过亲身经历来理解什么有趣，什么能触动内心，这是一种「模式」的积累。然后，将积累的这些模式进行组合和筛选，即使没有才能，也应该可以通过大量的知识和经验来弥补。因此，努力获取知识也可以被视为一种努力。而如何进行创新改进则取决于个人的“品味”。因此，在努力中，实际上需要额外的时间来面对「其他作品和体验中什么有趣」的问题，这是必要的。这不仅仅是关于「有趣的事物」，还需要吸收不有趣的事物，才能真正理解「它们为什么不好」。</p><p>这其实相当困难。许多人并不认为阅读大量漫画或观看动画片是一种努力。如果将这样的过程排除在外，只专注于自己的作品，将其视为「努力」，则可能会导致产生让人不想看的作品。这样来看，创作将会是作者此前所看所闻的综合，从某种意义上说，如果献身于创作的话，那么生活本身也可以被视为一种努力。</p><p>因此，「小说不是光努力就行的，对吧。」的言论虽然看似残酷，但却非常准确。如果某人积累了多种多样的「有趣或无趣」的模式，特别是这些模式学习的力量在没有明确努力的情况下被发挥，那么这个人可能会创作出创新之作。因此，在创作方面，是否「努力」只是一个明显的评价标准之一，而不是本质。</p><p>因为那天的令人震撼的对话，我一直在思考这一点。尽管我明白创作并不是仅仅根据「努力」这一点来判断的，但是一直没能讲得明白。</p><p>嘛，不过在合租室友的闲聊之中，完全没有必要使用这种严格的措辞。毕竟，合租屋是一个能够将每个人的笨拙之处也容纳的神奇的地方。</p><hr><p><img src="'+r+'" alt="" loading="lazy"><img src="https://img.tree-novel.com/talk/335eca61a57530666a5d235a06dbaaf9.jpg" alt="" loading="lazy"><img src="https://img.tree-novel.com/talk/946e608e195b1cb79973aab92ff8e9ae.jpg" alt="" loading="lazy"></p><blockquote><p>本周的にゃるら的物品：</p><p>【餐具】我喜欢夏洛酱说的那句台词「镇静心灵的香草茶」，所以我为了用温暖的红茶来宁静心灵而开始追求架子和餐具。不过，由于我没有嗅觉，所以无法真正理解茶的魅力，包括香气在内。我所做的一切不过是在模仿夏洛酱而已。</p></blockquote>',17);function b(x,y){const p=o("ExternalLinkIcon"),n=o("RouterLink");return s(),_("div",null,[i(" more "),u,e("p",null,[t("原文链接："),e("a",h,[t("第30回／努力とセンスの違いの残酷さ"),a(p)])]),e("blockquote",null,[k,e("p",null,[a(n,{to:"/posts/Translate/nyalra_kb_29.html"},{default:m(()=>[t("【奈亚拉面壁自语】第29回｜妄加评论会使账号腐烂【230606】")]),_:1})])]),g])}const z=c(f,[["render",b],["__file","nyalra_kb_30.html.vue"]]);export{z as default};
